import React, { useState, useEffect } from 'react';
import {
  Users, UserCircle, Stethoscope, Search, FileText, Trash2, Lock,
  Beaker, Pill, ShoppingBag, CheckCircle2, Activity, IndianRupee, LogOut
} from 'lucide-react';

const DEPARTMENTS = [
  { id: 'CARD', name: 'Cardiology' }, { id: 'GYN', name: 'Gynecology' },
  { id: 'OPH', name: 'Ophthalmology' }, { id: 'PED', name: 'Pediatrics' },
  { id: 'ORTHO', name: 'Orthopedics' }, { id: 'DERM', name: 'Dermatology' },
  { id: 'NEURO', name: 'Neurology' }, { id: 'ENT', name: 'ENT' },
  { id: 'DENT', name: 'Dental' }, { id: 'GEN', name: 'General Medicine' }
];

const WAIT_PER_PATIENT = 20;

const LoginView = ({ handleLogin, loginForm, setLoginForm, view }) => (
  <div className="flex items-center justify-center mt-20">
    <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 w-full max-w-md">
      <div className="flex justify-center mb-6 text-blue-600"><Lock size={48} /></div>
      <h2 className="text-2xl font-black text-center mb-6 uppercase tracking-tight">
        {view} Login
      </h2>
      <form onSubmit={handleLogin} className="space-y-4">
        <input
          required
          placeholder="Username"
          value={loginForm.username}
          className="w-full p-4 border rounded-2xl bg-slate-50 outline-none focus:ring-2 ring-blue-500"
          onChange={e => setLoginForm({ ...loginForm, username: e.target.value })}
        />
        <input
          required
          type="password"
          placeholder="Password"
          value={loginForm.password}
          className="w-full p-4 border rounded-2xl bg-slate-50 outline-none focus:ring-2 ring-blue-500"
          onChange={e => setLoginForm({ ...loginForm, password: e.target.value })}
        />
        <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black hover:bg-blue-700 transition shadow-lg">Access Dashboard</button>
      </form>
    </div>
  </div>
);

export default function SmartHospital() {
  const [view, setView] = useState('patient');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });

  // Persistent States
  const [patients, setPatients] = useState(() => JSON.parse(localStorage.getItem('hospital_patients')) || []);
  const [serving, setServing] = useState(() => JSON.parse(localStorage.getItem('hospital_serving')) || DEPARTMENTS.reduce((a, d) => ({ ...a, [d.id]: 0 }), {}));
  const [deptTokenCounters, setDeptTokenCounters] = useState(() => JSON.parse(localStorage.getItem('hospital_counters')) || DEPARTMENTS.reduce((a, d) => ({ ...a, [d.id]: 1 }), {}));
  const [labRequests, setLabRequests] = useState(() => JSON.parse(localStorage.getItem('hospital_lab')) || []);
  const [prescriptions, setPrescriptions] = useState(() => JSON.parse(localStorage.getItem('hospital_prescriptions')) || []);

  const [formData, setFormData] = useState({ name: '', phone: '', age: '', gender: 'Male', address: '', complaint: '', deptId: 'CARD', bp: '', temp: '' });
  const [searchToken, setSearchToken] = useState('');
  const [labInputs, setLabInputs] = useState({});
  const [medInputs, setMedInputs] = useState({});

  useEffect(() => { localStorage.setItem('hospital_patients', JSON.stringify(patients)); }, [patients]);
  useEffect(() => { localStorage.setItem('hospital_serving', JSON.stringify(serving)); }, [serving]);
  useEffect(() => { localStorage.setItem('hospital_counters', JSON.stringify(deptTokenCounters)); }, [deptTokenCounters]);
  useEffect(() => { localStorage.setItem('hospital_lab', JSON.stringify(labRequests)); }, [labRequests]);
  useEffect(() => { localStorage.setItem('hospital_prescriptions', JSON.stringify(prescriptions)); }, [prescriptions]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (loginForm.username === 'harisai' && loginForm.password === 'harisai@1234') {
      setIsAuthenticated(true);
    } else {
      alert("Invalid Credentials!");
    }
  };

  const logout = () => {
    setIsAuthenticated(false);
    setView('patient');
    setLoginForm({ username: '', password: '' });
  };

  const registerPatient = (e) => {
    e.preventDefault();
    const tokenNumber = deptTokenCounters[formData.deptId];
    const displayToken = `${formData.deptId}-${tokenNumber}`;
    const newToken = {
      displayToken,
      tokenNumber,
      ...formData,
      status: 'Waiting',
      timeJoined: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    setPatients([...patients, newToken]);
    setDeptTokenCounters(prev => ({ ...prev, [formData.deptId]: prev[formData.deptId] + 1 }));
    setFormData({ name: '', phone: '', age: '', gender: 'Male', address: '', complaint: '', deptId: 'CARD', bp: '', temp: '' });
    alert(`Token issued: ${displayToken}`);
  };

  const saveDoctorFindings = (deptId, patient) => {
    if (!patient) return alert("Please select a patient first!");

    if (labInputs[deptId]) {
      setLabRequests(prev => [...prev, {
        id: Date.now() + 1,
        token: patient.displayToken,
        name: patient.name,
        test: labInputs[deptId],
        status: 'Pending'
      }]);
    }
    if (medInputs[deptId]) {
      setPrescriptions(prev => [...prev, {
        id: Date.now() + 2,
        token: patient.displayToken,
        name: patient.name,
        meds: medInputs[deptId],
        status: 'Pending'
      }]);
    }

    setLabInputs({ ...labInputs, [deptId]: '' });
    setMedInputs({ ...medInputs, [deptId]: '' });
    alert("Sent to Lab & Pharmacy!");
  };

  const nextPatient = (dId) => {
    const nextTokenNum = serving[dId] + 1;
    if (patients.some(p => p.deptId === dId && p.tokenNumber === nextTokenNum)) {
      setServing(prev => ({ ...prev, [dId]: nextTokenNum }));
    } else {
      alert(`Queue empty for ${dId}`);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans pb-20">
      <nav className="bg-white shadow-sm p-4 flex justify-center gap-2 md:gap-4 border-b sticky top-0 z-50 flex-wrap">
        {[
          { id: 'doctor', icon: <Stethoscope size={18} />, label: 'Doctors' },
          { id: 'manager', icon: <Users size={18} />, label: 'Staff' },
          { id: 'lab', icon: <Beaker size={18} />, label: 'Lab' },
          { id: 'pharmacy', icon: <Pill size={18} />, label: 'Pharmacy' },
          { id: 'billing', icon: <IndianRupee size={18} />, label: 'Billing' },
          { id: 'patient', icon: <UserCircle size={18} />, label: 'Tracker' },
        ].map(btn => (
          <button
            key={btn.id}
            onClick={() => { setView(btn.id); setIsAuthenticated(false); }}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl transition font-bold ${view === btn.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-100'}`}
          >
            {btn.icon} <span className="hidden sm:inline">{btn.label}</span>
          </button>
        ))}
        {isAuthenticated && (
          <button onClick={logout} className="flex items-center gap-2 text-red-500 font-bold border-l pl-4 hover:bg-red-50 px-3 rounded-xl">
            <LogOut size={18} /> <span className="hidden sm:inline">Logout</span>
          </button>
        )}
      </nav>

      <main className="p-6 max-w-7xl mx-auto">
        {(view !== 'patient' && view !== 'billing') && !isAuthenticated ? (
          <LoginView handleLogin={handleLogin} loginForm={loginForm} setLoginForm={setLoginForm} view={view} />
        ) : (
          <>
            {/* DOCTOR VIEW */}
            {view === 'doctor' && (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {DEPARTMENTS.map(d => {
                  const currentPatient = patients.find(p => p.deptId === d.id && p.tokenNumber === serving[d.id]);
                  return (
                    <div key={d.id} className="bg-white p-6 rounded-[2rem] border shadow-sm">
                      <h3 className="font-black text-xl mb-4">{d.name}</h3>
                      <div className="text-center py-4 bg-slate-900 text-white rounded-2xl mb-4">
                        <p className="text-[10px] opacity-50 uppercase font-black tracking-widest">Token</p>
                        <p className="text-4xl font-black">{d.id}-{serving[d.id]}</p>
                      </div>

                      {currentPatient ? (
                        <div className="bg-blue-50/50 p-4 rounded-2xl mb-4 border border-blue-100">
                          <p className="text-lg font-bold">{currentPatient.name}</p>
                          <p className="text-sm text-slate-500 italic mb-2">"{currentPatient.complaint}"</p>
                        </div>
                      ) : <p className="text-center text-slate-400 text-sm py-4">No Active Patient</p>}

                      <div className="space-y-2 mb-4">
                        <input placeholder="Tests..." value={labInputs[d.id] || ''} onChange={e => setLabInputs({ ...labInputs, [d.id]: e.target.value })} className="w-full border rounded-xl px-4 py-3 bg-slate-50 outline-none focus:ring-2 ring-blue-500" />
                        <input placeholder="Medicines..." value={medInputs[d.id] || ''} onChange={e => setMedInputs({ ...medInputs, [d.id]: e.target.value })} className="w-full border rounded-xl px-4 py-3 bg-slate-50 outline-none focus:ring-2 ring-emerald-500" />
                      </div>

                      <div className="grid grid-cols-2 gap-2">
                        <button onClick={() => nextPatient(d.id)} className="bg-slate-800 text-white py-3 rounded-xl font-bold">Next</button>
                        <button onClick={() => saveDoctorFindings(d.id, currentPatient)} className="bg-blue-600 text-white py-3 rounded-xl font-bold">Send</button>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}

            {/* LAB VIEW */}
            {view === 'lab' && (
              <div className="bg-white p-8 rounded-[2rem] shadow-sm border">
                <h2 className="text-2xl font-black mb-6 flex items-center gap-2"><Beaker className="text-blue-600" /> Lab Portal</h2>
                <div className="space-y-3">
                  {labRequests.filter(r => r.status === 'Pending').map(req => (
                    <div key={req.id} className="flex justify-between items-center p-5 bg-slate-50 rounded-2xl border">
                      <div><p className="font-black text-blue-600">{req.token}</p><p className="font-bold">{req.name}</p><p className="text-sm">Test: {req.test}</p></div>
                      <button onClick={() => setLabRequests(labRequests.map(r => r.id === req.id ? { ...r, status: 'Done' } : r))} className="bg-emerald-500 text-white px-6 py-2 rounded-xl font-bold">Done</button>
                    </div>
                  ))}
                  {labRequests.filter(r => r.status === 'Pending').length === 0 && <p className="text-center py-10 text-slate-400 italic">No pending tests</p>}
                </div>
              </div>
            )}

            {/* PHARMACY VIEW */}
            {view === 'pharmacy' && (
              <div className="bg-white p-8 rounded-[2rem] shadow-sm border">
                <h2 className="text-2xl font-black mb-6 flex items-center gap-2"><Pill className="text-emerald-600" /> Pharmacy Portal</h2>
                <div className="space-y-3">
                  {prescriptions.filter(p => p.status === 'Pending').map(pre => (
                    <div key={pre.id} className="flex justify-between items-center p-5 bg-slate-50 rounded-2xl border">
                      <div><p className="font-black text-emerald-600">{pre.token}</p><p className="font-bold">{pre.name}</p><p className="text-sm">Meds: {pre.meds}</p></div>
                      <button onClick={() => setPrescriptions(prescriptions.map(p => p.id === pre.id ? { ...p, status: 'Dispensed' } : p))} className="bg-blue-600 text-white px-6 py-2 rounded-xl font-bold">Dispense</button>
                    </div>
                  ))}
                  {prescriptions.filter(p => p.status === 'Pending').length === 0 && <p className="text-center py-10 text-slate-400 italic">No pending prescriptions</p>}
                </div>
              </div>
            )}

            {/* MANAGER VIEW */}
            {view === 'manager' && (
              <div className="grid lg:grid-cols-5 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[2rem] shadow-sm border h-fit">
                  <h2 className="text-2xl font-black mb-6">OPD Registration</h2>
                  <form onSubmit={registerPatient} className="space-y-4">
                    <input required value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} placeholder="Patient Name" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none" />
                    <div className="grid grid-cols-2 gap-4">
                      <input required value={formData.age} onChange={e => setFormData({ ...formData, age: e.target.value })} placeholder="Age" className="w-full p-4 border rounded-2xl bg-slate-50" />
                      <select value={formData.deptId} onChange={e => setFormData({ ...formData, deptId: e.target.value })} className="w-full p-4 border rounded-2xl bg-slate-50">
                        {DEPARTMENTS.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                      </select>
                    </div>
                    <textarea required value={formData.complaint} onChange={e => setFormData({ ...formData, complaint: e.target.value })} placeholder="Complaint" className="w-full p-4 border rounded-2xl bg-slate-50" rows="2" />
                    <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-lg">Issue Token</button>
                  </form>
                </div>
                <div className="lg:col-span-3">
                  <div className="bg-white p-6 rounded-[2rem] border shadow-sm h-full max-h-[600px] overflow-y-auto">
                    <div className="flex justify-between items-center mb-6">
                      <h2 className="text-xl font-black">All Tokens Today</h2>
                      <button onClick={() => setPatients([])} className="text-red-500 hover:bg-red-50 p-2 rounded-lg transition"><Trash2 size={20} /></button>
                    </div>
                    <div className="space-y-3">
                      {patients.slice().reverse().map(p => (
                        <div key={p.displayToken} className="p-4 bg-slate-50 rounded-2xl flex justify-between items-center border">
                          <div><p className="font-black text-blue-600">{p.displayToken}</p><p className="font-bold">{p.name}</p></div>
                          <span className="text-[10px] font-black bg-slate-200 px-3 py-1 rounded-full">{p.deptId}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            )}

            {/* BILLING VIEW */}
            {view === 'billing' && (
              <div className="max-w-4xl mx-auto bg-white p-8 rounded-[2rem] shadow-sm border">
                <h2 className="text-3xl font-black mb-8 flex items-center gap-2"><IndianRupee className="text-emerald-600" /> Billing Desk</h2>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead><tr className="border-b text-slate-400 text-sm"><th className="pb-4">Token</th><th className="pb-4">Name</th><th className="pb-4">Fee</th><th className="pb-4">Action</th></tr></thead>
                    <tbody>
                      {patients.map(p => (
                        <tr key={p.displayToken} className="border-b last:border-0 text-sm">
                          <td className="py-4 font-black">{p.displayToken}</td>
                          <td className="py-4 font-bold">{p.name}</td>
                          <td className="py-4">₹ 500.00</td>
                          <td className="py-4"><button onClick={() => alert("Paid!")} className="text-blue-600 font-black">Collect</button></td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {/* PATIENT TRACKER */}
            {view === 'patient' && (
              <div className="max-w-xl mx-auto text-center mt-12">
                <h1 className="text-5xl font-black text-slate-900 mb-10 tracking-tighter">Live Queue</h1>
                <div className="relative mb-12">
                  <input type="text" onChange={(e) => setSearchToken(e.target.value.toUpperCase())} placeholder="Search Your Token (e.g. CARD-1)" className="w-full p-6 pl-16 border-2 border-slate-200 rounded-3xl text-2xl font-black focus:border-blue-500 outline-none uppercase shadow-sm" />
                  <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300" size={32} />
                </div>
                {searchToken && patients.find(p => p.displayToken === searchToken) ? (
                  (() => {
                    const p = patients.find(p => p.displayToken === searchToken);
                    const opsAhead = p.tokenNumber - serving[p.deptId];
                    return opsAhead > 0 ? (
                      <div className="bg-white p-10 rounded-[3rem] shadow-2xl border">
                        <div className="flex justify-around items-center mb-8">
                          <div><p className="text-xs text-slate-400 font-bold mb-1">CURRENTLY AT</p><p className="text-5xl font-black">{p.deptId}-{serving[p.deptId]}</p></div>
                          <div className="w-px h-12 bg-slate-100"></div>
                          <div><p className="text-xs text-slate-400 font-bold mb-1">YOUR TOKEN</p><p className="text-5xl font-black text-blue-600">{p.displayToken}</p></div>
                        </div>
                        <p className="bg-blue-50 p-4 rounded-2xl font-black text-blue-700">~{opsAhead * WAIT_PER_PATIENT}m Est. Wait Time</p>
                      </div>
                    ) : <div className="bg-emerald-600 text-white p-12 rounded-[3rem] text-3xl font-black shadow-xl animate-pulse">YOUR TURN! PROCEED TO DOCTOR</div>;
                  })()
                ) : searchToken ? <p className="text-slate-400 font-bold italic">Token not found</p> : null}
              </div>
            )}
          </>
        )}
      </main>
    </div>
  );
}
